static int growable_write(int output, FILE *userp) {
    struct string_store *store = (struct string_store *)userp;
    char outch = (char)output;

    if (store->ptr == NULL) {
        store->ptr = malloc(64);
        if (!store->ptr) {
            store->failed = 1;
            return -1;
        }
        store->allocated = 64;
        store->used = 0;
    }

    if (store->used == store->allocated - 1) {
        size_t new_size = store->allocated + store->allocated / 2;
        char *new_ptr = realloc(store->ptr, new_size);
        if (!new_ptr) {
            store->failed = 1;
            return -1;
        }
        store->ptr = new_ptr;
        store->allocated = new_size;
    }

    store->ptr[store->used] = outch;
    store->used++;

    if (store->used == store->allocated) {
        store->ptr[store->used - 1] = '\0';
    }

    return outch;
}

